const now = new Date();
const hasWebhookEnvelope = Boolean($json && (Object.prototype.hasOwnProperty.call($json, 'body') || Object.prototype.hasOwnProperty.call($json, 'headers')));
const req = hasWebhookEnvelope ? ($json.body || {}) : ($json || {});
const endDefault = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate(), 0, 0, 0, 0));
const startDefault = new Date(endDefault);
startDefault.setUTCDate(startDefault.getUTCDate() - 1);
const startRaw = req.start_utc || req.window_start_utc || null;
const endRaw = req.end_utc || req.window_end_utc || null;
const start = startRaw ? new Date(startRaw) : startDefault;
const end = endRaw ? new Date(endRaw) : endDefault;
return [{ json: { start_utc: start.toISOString(), end_utc: end.toISOString(), run_ts: now.toISOString(), forced_workspace_id: req.workspace_id || null, trigger_mode: hasWebhookEnvelope ? 'webhook' : 'schedule' } }];

const raw = $input.all().map(i => i.json);
const rows = [];
for (const r of raw) {
  if (Array.isArray(r)) rows.push(...r);
  else if (Array.isArray(r?.body)) rows.push(...r.body);
  else if (r && typeof r === 'object' && ('solution_id' in r || 'engagement_count' in r)) rows.push(r);
}
const w = $node['W3 Compute Yesterday Window'].json;
return [{ json: { start_utc: w.start_utc, end_utc: w.end_utc, feedback: rows } }];

const raw = $input.all().map(i => i.json);
const rows = [];
for (const r of raw) {
  if (Array.isArray(r)) rows.push(...r);
  else if (Array.isArray(r?.body)) rows.push(...r.body);
  else if (r && typeof r === 'object' && ('id' in r || 'confidence_score' in r)) rows.push(r);
}
const w = $node['W3 Compute Yesterday Window'].json;
return [{ json: { start_utc: w.start_utc, end_utc: w.end_utc, solutions: rows } }];

const all = $input.all().map(i => i.json);
const f = all.find(x => x.feedback) || {};
const s = all.find(x => x.solutions) || {};
const feedback = Array.isArray(f.feedback) ? f.feedback : [];
const solutions = Array.isArray(s.solutions) ? s.solutions : [];
const start_utc = f.start_utc || s.start_utc || $node['W3 Compute Yesterday Window'].json.start_utc;
const end_utc = f.end_utc || s.end_utc || $node['W3 Compute Yesterday Window'].json.end_utc;
const bySolution = new Map();
for (const row of solutions) bySolution.set(String(row.id), row);
const toNum = (v) => { const n = Number(v); return Number.isFinite(n) ? n : 0; };
const wsMap = new Map();
for (const fb of feedback) {
  const sol = bySolution.get(String(fb.solution_id)) || {};
  const workspace = String(fb.workspace_id || sol.workspace_id || 'unknown_workspace');
  const channel = String(fb.channel || sol.channel || 'unspecified');
  const tone = String(fb.tone_recommendation || sol.tone_recommendation || 'unspecified');
  const engagement = Math.max(0, toNum(fb.engagement_count));
  const conversions = Math.max(0, toNum(fb.conversions));
  const score = engagement + (conversions * 20);
  if (!wsMap.has(workspace)) {
    wsMap.set(workspace, { channel: new Map(), tone: new Map(), samples: 0 });
  }
  const agg = wsMap.get(workspace);
  agg.samples += 1;

  if (!agg.channel.has(channel)) agg.channel.set(channel, { wins: 0, total: 0, engagement_sum: 0, score_sum: 0 });
  const c = agg.channel.get(channel);
  c.total += 1;
  c.engagement_sum += engagement;
  c.score_sum += score;
  if (conversions > 0) c.wins += 1;

  if (!agg.tone.has(tone)) agg.tone.set(tone, { wins: 0, total: 0, engagement_sum: 0, score_sum: 0 });
  const t = agg.tone.get(tone);
  t.total += 1;
  t.engagement_sum += engagement;
  t.score_sum += score;
  if (conversions > 0) t.wins += 1;
}

const updates = [];
const nowIso = new Date().toISOString();
for (const [workspace_id, agg] of wsMap.entries()) {
  const channel_scores = {};
  for (const [key, v] of agg.channel.entries()) {
    channel_scores[key] = {
      wins: v.wins,
      total: v.total,
      engagement_sum: v.engagement_sum,
      win_rate: Number((v.total ? v.wins / v.total : 0).toFixed(4)),
      avg_score: Number((v.total ? v.score_sum / v.total : 0).toFixed(4))
    };
  }
  const tone_scores = {};
  for (const [key, v] of agg.tone.entries()) {
    tone_scores[key] = {
      wins: v.wins,
      total: v.total,
      engagement_sum: v.engagement_sum,
      win_rate: Number((v.total ? v.wins / v.total : 0).toFixed(4)),
      avg_score: Number((v.total ? v.score_sum / v.total : 0).toFixed(4))
    };
  }
  updates.push({
    workspace_id,
    winning_channels_json: channel_scores,
    winning_tones_json: tone_scores,
    updated_at: nowIso,
    sample_count: agg.samples
  });
}

return [{ json: { start_utc, end_utc, workspace_count: updates.length, workspace_updates: updates } }];

const base = $node['W3 Compute Winning Patterns'].json;
let updated = 0;
let upsert_node_executed = true;
try {
  const upsertItems = $items('W3 Upsert brand_memory');
  updated = Array.isArray(upsertItems) ? upsertItems.length : 0;
} catch (e) {
  updated = 0;
  upsert_node_executed = false;
}
const ranked = Number(base.workspace_count || 0);
return [{
  json: {
    start_utc: base.start_utc,
    end_utc: base.end_utc,
    workspaces_ranked: ranked,
    workspaces_updated: updated,
    workspaces_failed: Math.max(ranked - updated, 0),
    upsert_node_executed,
    trigger_mode: String($node['W3 Compute Yesterday Window'].json.trigger_mode || 'schedule'),
    completed_at: new Date().toISOString()
  }
}];
